import sailpoint.object.CustomGlobal;
import sailpoint.object.SailPointObject;
import org.apache.log4j.Level;
import org.apache.log4j.Logger;

Logger logger = Logger.getLogger(loggerClass);  
CustomGlobal.put("UserSession",httpSession);

logger.debug("Start");
for (int i = 0; i < this.variables.length; i++) {
String name = this.variables[i];
if ("transient".equals(name)) {continue;}
Object value = eval(name);

if (value == void)
logger.trace(name + " = void");
else if (value == null) 
logger.trace(name + " = null");
else if (value instanceof SailPointObject) 
logger.trace(name + ": " + value);
else 
logger.trace(name + ": " + value.getClass().getSimpleName() + " = " + value);
}


import sailpoint.tools.Util;

Map wfArgsMap = new HashMap();
wfArgsMap.put("managersso", formModel.get("managerId"));
wfArgsMap.put("requesterNameId", requesterNameId);
wfArgsMap.put("requesterName", requesterName);

wfArgsMap.put("ADAccountOption", Util.atob(formModel.get("ADAccountOption")));

if (!Util.nullSafeCaseInsensitiveEq(requesterName,formModel.get("testAccountRequestOwner"))) {
wfArgsMap.put("requestee", formModel.get("testAccountRequestOwner"));
}

wfArgsMap.put("appid", formModel.get("firstNameTestUser"));
wfArgsMap.put("appName", formModel.get("lastNameTestUser"));

initiateWorkflow("Workflow_VSNT_Test_Account_Migration", wfArgsMap);

import org.apache.log4j.Level;
import org.apache.log4j.Logger;
Logger logger = Logger.getLogger(loggerClass);  

logger.debug("Stop");

List messages = wfcase.getMessages();            
if (messages != null) for (Message message : messages)
{
if (message.isError()) logger.error(message.toString());
else if (message.isWarning()) logger.warn(message.toString());
else logger.info(message.toString());
}
